const result = await api.getCurrentDatetime();
const currentDate = new Date(result.now);
const oneWeekAgo = new Date(currentDate);
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
const fromIso = oneWeekAgo.toISOString();
const toIso = currentDate.toISOString();
const txResult = await api.listTransactionsInWindow({ fromIso, toIso, limit: 10000 });
const txs = txResult.transactions;
const counts: Record<string, number> = {};
for (const tx of txs) {
  const id = tx.customerId;
  counts[id] = (counts[id] || 0) + 1;
}
let topId = "";
let maxTxs = 0;
for (const [cid, cnt] of Object.entries(counts)) {
  if (cnt > maxTxs) {
    maxTxs = cnt;
    topId = cid;
  }
}
const custResult = await api.getAllCustomers({ limit: 1000 });
const customers = custResult.customers;
const topCust = customers.find((c: any) => c.id === topId);
const name = topCust ? topCust.name : "";
const stats = await api.computeCustomerSpendStats({ customerId: topId, fromIso, toIso });
const finalResult = {
  topCustomerId: topId,
  topCustomerName: name,
  transactionCount: stats.transactionCount,
  totalSpend: stats.totalSpend,
  averageSpend: stats.averageSpend,
  fromIso: fromIso,
  toIso: toIso
};
finalResult;

